class LogObserver : DefaultLifecycleObserver {
    override fun onCreate(owner: LifecycleOwner)  { Log.d("LC", "CREATE") }
    override fun onStart(owner: LifecycleOwner)   { Log.d("LC", "START") }
    override fun onResume(owner: LifecycleOwner)  { Log.d("LC", "RESUME") }
    override fun onPause(owner: LifecycleOwner)   { Log.d("LC", "PAUSE") }
    override fun onStop(owner: LifecycleOwner)    { Log.d("LC", "STOP") }
    override fun onDestroy(owner: LifecycleOwner) { Log.d("LC", "DESTROY") }
}

class MyActivity : AppCompatActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        lifecycle.addObserver(LogObserver())
    }
}

